INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Knee_Tuck_Jump','Knee Tuck Jump','isquiotibiales',ARRAY['abductores','aductores','pantorrillas','glúteos','cuádriceps'],'peso corporal','plyometrics',ARRAY['Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position.','Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands.','Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend.'],'Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position. Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands. Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Tuck_Jump/0.jpg','exercisedb',true),('Kneeling_Arm_Drill','Kneeling Arm Drill','hombros',ARRAY['abdominales'],NULL,'plyometrics',ARRAY['This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated.','Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint.','As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible.','Switch knees and repeat.'],'This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated. Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint. As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible. Switch knees and repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Arm_Drill/0.jpg','exercisedb',true),('Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists','Kneeling Cable Crunch With Alternating Oblique Twists','abdominales',ARRAY[]::text[],'cable','strength',ARRAY['Connect a rope attachment to a high pulley cable and position a mat on the floor in front of it.','Grab the rope with both hands and kneel approximately two feet back from the tower.','Position the rope behind your head with your hands by your ears.','Keep your hands in the same place, contract your abs and pull downward on the rope in a crunching movement until your elbows reach your knees.','Pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position.','Repeat the same downward movement until you''''re halfway down, at which time you''''ll begin rotating one of your elbows to the opposite knee.','Again, pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position.','Repeat the same movement as before, but alternate the other elbow to the opposite knee.','Continue this series of movements to failure.'],'Connect a rope attachment to a high pulley cable and position a mat on the floor in front of it. Grab the rope with both hands and kneel approximately two feet back from the tower. Position the rope behind your head with your hands by your ears. Keep your hands in the same place, contract your abs and pull downward on the rope in a crunching movement until your elbows reach your knees. Pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position. Repeat the same downward movement until you''re halfway down, at which time you''ll begin rotating one of your elbows to the opposite knee. Again, pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position. Repeat the same movement as before, but alternate the other elbow to the opposite knee. Continue this series of movements to failure.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists/0.jpg','exercisedb',true),('Kneeling_Cable_Triceps_Extension','Kneeling Cable Triceps Extension','tríceps',ARRAY[]::text[],'cable','strength',ARRAY['Place a bench sideways in front of a high pulley machine.','Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down.','Face away from the machine and kneel.','Place your head and the back of your upper arms on the bench. Your elbows should be bent with the forearms pointing towards the high pulley. This will be your starting position.','While keeping your upper arms close to your head at all times with the elbows in, press the bar out in a semicircular motion until the elbows are locked and your arms are parallel to the floor. Contract the triceps hard and keep this position for a second. Exhale as you perform this movement.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'],'Place a bench sideways in front of a high pulley machine. Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down. Face away from the machine and kneel. Place your head and the back of your upper arms on the bench. Your elbows should be bent with the forearms pointing towards the high pulley. This will be your starting position. While keeping your upper arms close to your head at all times with the elbows in, press the bar out in a semicircular motion until the elbows are locked and your arms are parallel to the floor. Contract the triceps hard and keep this position for a second. Exhale as you perform this movement. Slowly return to the starting position as you breathe in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Triceps_Extension/0.jpg','exercisedb',true),('Kneeling_Forearm_Stretch','Kneeling Forearm Stretch','antebrazos',ARRAY[]::text[],NULL,'stretching',ARRAY['Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees.','Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds.'],'Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees. Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Forearm_Stretch/0.jpg','exercisedb',true),('Kneeling_High_Pulley_Row','Kneeling High Pulley Row','dorsales',ARRAY['bíceps','espalda media'],'cable','strength',ARRAY['Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.','Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.','After pausing briefly, slowly return to the starting position.'],'Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position. Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out. After pausing briefly, slowly return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_High_Pulley_Row/0.jpg','exercisedb',true),('Kneeling_Hip_Flexor','Kneeling Hip Flexor','cuádriceps',ARRAY['cuádriceps'],NULL,'stretching',ARRAY['Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor.','Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side.'],'Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor. Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Hip_Flexor/0.jpg','exercisedb',true),('Kneeling_Jump_Squat','Kneeling Jump Squat','glúteos',ARRAY['pantorrillas','isquiotibiales','cuádriceps'],'barra','olympic weightlifting',ARRAY['Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier.','Sit back with your hips until your glutes touch your feet, keeping your head and chest up.','Explode up with your hips, generating enough power to land with your feet flat on the floor.','Continue with the squat by driving through your heels and extending the knees to come to a standing position.'],'Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier. Sit back with your hips until your glutes touch your feet, keeping your head and chest up. Explode up with your hips, generating enough power to land with your feet flat on the floor. Continue with the squat by driving through your heels and extending the knees to come to a standing position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Jump_Squat/0.jpg','exercisedb',true),('Kneeling_Single-Arm_High_Pulley_Row','Kneeling Single-Arm High Pulley Row','dorsales',ARRAY['bíceps','espalda media'],'cable','strength',ARRAY['Attach a single handle to a high pulley and make your weight selection.','Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position.','Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you.','After a brief pause, return to the starting position.'],'Attach a single handle to a high pulley and make your weight selection. Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position. Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you. After a brief pause, return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Single-Arm_High_Pulley_Row/0.jpg','exercisedb',true),('Kneeling_Squat','Kneeling Squat','glúteos',ARRAY['abdominales','isquiotibiales','espalda baja'],'barra','powerlifting',ARRAY['Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight.','With your head looking forward, sit back with your butt until you touch your calves.','Reverse the motion, returning the torso to an upright position.'],'Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight. With your head looking forward, sit back with your butt until you touch your calves. Reverse the motion, returning the torso to an upright position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Squat/0.jpg','exercisedb',true);